-- 楽曲データ (songs) と楽曲メンバー紐付け (song_juniors) のシードデータ。
-- 同じIDで再実行した場合は、既存行を最新の内容へ更新する。

BEGIN;

-- 古いスクリプト seed.mjs 由来の Sample Song 1〜5 を削除する。
-- 現在の正本は a0b1c2d3-0001〜0040 の40曲seed。
DELETE FROM public.song_comments
WHERE song_id IN (
    'd3b07384-d113-4956-a5cc-e5b1574a4f81',
    'd3b07384-d113-4956-a5cc-e5b1574a4f82',
    'd3b07384-d113-4956-a5cc-e5b1574a4f83',
    'd3b07384-d113-4956-a5cc-e5b1574a4f84',
    'd3b07384-d113-4956-a5cc-e5b1574a4f85'
);

DELETE FROM public.song_likes
WHERE song_id IN (
    'd3b07384-d113-4956-a5cc-e5b1574a4f81',
    'd3b07384-d113-4956-a5cc-e5b1574a4f82',
    'd3b07384-d113-4956-a5cc-e5b1574a4f83',
    'd3b07384-d113-4956-a5cc-e5b1574a4f84',
    'd3b07384-d113-4956-a5cc-e5b1574a4f85'
);

DELETE FROM public.song_juniors
WHERE song_id IN (
    'd3b07384-d113-4956-a5cc-e5b1574a4f81',
    'd3b07384-d113-4956-a5cc-e5b1574a4f82',
    'd3b07384-d113-4956-a5cc-e5b1574a4f83',
    'd3b07384-d113-4956-a5cc-e5b1574a4f84',
    'd3b07384-d113-4956-a5cc-e5b1574a4f85'
);

DELETE FROM public.support_point_logs
WHERE source_type = 'song'
  AND source_id IN (
      'd3b07384-d113-4956-a5cc-e5b1574a4f81',
      'd3b07384-d113-4956-a5cc-e5b1574a4f82',
      'd3b07384-d113-4956-a5cc-e5b1574a4f83',
      'd3b07384-d113-4956-a5cc-e5b1574a4f84',
      'd3b07384-d113-4956-a5cc-e5b1574a4f85'
  );

DELETE FROM public.songs
WHERE id IN (
    'd3b07384-d113-4956-a5cc-e5b1574a4f81',
    'd3b07384-d113-4956-a5cc-e5b1574a4f82',
    'd3b07384-d113-4956-a5cc-e5b1574a4f83',
    'd3b07384-d113-4956-a5cc-e5b1574a4f84',
    'd3b07384-d113-4956-a5cc-e5b1574a4f85'
);

